  vec2 uv3 = vec2(vUv.x+.2+(audioMid*.1)+(.3*q1),vUv.y+.2+(audioMid*.1)+(.3*q2));
  vec3 ret3 = texture(sampler_ruin, ((uv3)*uAspect.xy)*(.7-(audioMid*.05))).xyz;
